import { tw } from '@utils/useTailwind';
import { clsx } from 'clsx';
import { ChangeEvent, ReactNode, useCallback, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import InfiniteScroll from 'react-infinite-scroll-component';
import { Button } from '../../Button';
import { InputControl } from '../../InputControl';
import { AddIcon } from '../../icons';
import { Label } from '../../Label';
import { Loading } from '../../Loading';
import { useDisclosure } from '../../Modal';
import { Popover, PopoverContent, PopoverTrigger } from '../Popover';

type AddItemPopoverProps<ItemType> = WithChildren & {
  buttonText: string;
  closeOnSelect?: boolean;
  disableWhenListIsEmpty?: boolean;
  emptyListComponent?: ReactNode;
  fetchMoreItems?: () => void;
  hasMoreItems?: boolean;
  isLoading?: boolean;
  items?: ItemType[];
  onAddItem?: (item: ItemType) => void;
  onItemSearch?: (search: string) => void;
  searchString?: string;
};

export const AddItemPopover = <
  ItemType extends { id?: string; isPending?: boolean; name?: string },
>({
  buttonText,
  children,
  closeOnSelect = false,
  disableWhenListIsEmpty = true,
  emptyListComponent,
  fetchMoreItems,
  hasMoreItems,
  isLoading,
  items,
  onAddItem,
  onItemSearch,
  searchString,
}: AddItemPopoverProps<ItemType>) => {
  const { t } = useTranslation('common');

  const { isOpen, onClose, onToggle } = useDisclosure();

  const handleClose = useCallback(() => {
    onItemSearch?.('');
    onClose();
  }, [onClose, onItemSearch]);

  useEffect(() => {
    if (!isLoading && items?.length === 0 && (!onItemSearch || !searchString)) {
      handleClose();
    }
  }, [onItemSearch, items, handleClose, searchString, isLoading]);

  const listItems = useMemo(
    () =>
      items?.map((item) => (
        <Button
          aria-label={t('button.addItem', { itemName: item.name })}
          className={clsx(
            tw`flex items-center justify-between rounded-none bg-neutral-0 p-2 text-base first-of-type:rounded-t-lg
            last-of-type:rounded-b-lg hover:bg-neutral-200`
          )}
          isDisabled={item.isPending}
          key={item.id}
          onClick={() => {
            onAddItem?.(item);
            if (closeOnSelect) {
              onClose();
            }
          }}
          variant="unstyled"
        >
          <Label className="overflow-hidden text-ellipsis whitespace-nowrap">{item.name}</Label>
          {item.isPending ? <Loading size="xs" /> : <AddIcon className="w-[16px]" />}
        </Button>
      )),
    [items, closeOnSelect, onClose, onAddItem, t]
  );

  return (
    <Popover isOpen={isOpen} onClose={handleClose} placement="bottom">
      <PopoverTrigger
        className="mt-4 w-full [&[data-state=open]]:!text-neutral-700"
        disabled={disableWhenListIsEmpty && items?.length === 0}
        isActive={isOpen}
        onClick={onToggle}
        variant="secondary"
      >
        <AddIcon className="me-1 w-[15px]" />
        {buttonText}
      </PopoverTrigger>
      <PopoverContent className="z-[10001] w-full min-w-max rounded-lg border border-blue-500 p-0 shadow-[0px_14px_72px_#0A0F1C]">
        <div className="flex w-full flex-col">
          {onItemSearch && (
            <div className="m-2">
              <InputControl
                name="filter-items"
                onChange={(event: ChangeEvent<HTMLInputElement>) =>
                  onItemSearch(event.target.value)
                }
                placeholder={t('search')}
                type="search"
                value={searchString}
                variant="outline"
              />
            </div>
          )}
          {fetchMoreItems ? (
            <InfiniteScroll
              dataLength={(items || []).length}
              hasMore={!!hasMoreItems}
              height={200}
              loader={<Loading />}
              next={fetchMoreItems}
              scrollThreshold="200px"
            >
              {listItems}
            </InfiniteScroll>
          ) : (
            <div className="flex max-h-[200px] w-full flex-col overflow-y-auto">
              {listItems}
              {!listItems?.length ? emptyListComponent : null}
              {isLoading ? (
                <div className="py-4">
                  <Loading />
                </div>
              ) : null}
            </div>
          )}
          {children}
        </div>
      </PopoverContent>
    </Popover>
  );
};

